<template>
    <view>
        <view class="item">
            <view class="title">
                利用規約
            </view>
            <view class="contents">
                <u-textarea border="none" v-model="i1" disabled autoHeight></u-textarea>
            </view>
        </view>
        <view class="item">
            <view class="title">
                プライバシーポリシー
            </view>
            <view class="contents">
                <u-textarea border="none" v-model="i2" disabled autoHeight></u-textarea>
            </view>
        </view>
    </view>
</template>

<script>
    import {getConfig} from "@/api/index.js"
    export default {
        data() {
            return {
                i1:"",
                i2:""
            };
        },
        created() {
            this.getConfig()
        },
        methods:{
            getConfig(){
                let that = this
                getConfig().then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        that.i1 = res.data.config.privacy_policy
                        that.i2 = res.data.config.service_regulations
                    }
                })
            }
        }
    }
</script>

